  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_URL\")\n}\n\n// ==========================================\n// USER MODEL\n// ==========================================\nmodel User {\n  id          String   @id @default(uuid())\n  email       String   @unique\n  name        String?\n  avatar      String? // Supabase bucket se image ka URL aayega\n  about       String? // User ka short bio / description\n  phone       String? // Contact Number\n  address     String? // Creator Address\n  legalName   String? // Official Name for Payments\n  instagram   String? // Social Link\n  youtube     String? // Social Link\n  category    String? // Teaching Category\n  experience  String? // Years of Experience\n  upiId       String? // Creator payout UPI\n  bankAccount String? // Creator payout Bank Account details\n  role        Role     @default(STUDENT)\n  isVerified  Boolean  @default(false) // For Creator Verification by Admin\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  purchases Purchase[] // User ne jo courses kharide\n  progress  Progress[] // User ne kaunsi videos dekh li\n  cart      Cart? // User ka cart\n  courses   Course[] // Creator ke courses\n}\n\nenum Role {\n  STUDENT\n  CREATOR\n  ADMIN\n}\n\n// ==========================================\n// COURSE MODEL\n// ==========================================\nmodel Course {\n  id          String   @id @default(uuid())\n  title       String\n  description String\n  outcomes    String[] // What You'll Learn bullet points\n  price       Float // Ex: 499.0\n  category    String // Ex: 'business', 'finance', 'ncert'\n  thumbnail   String? // Supabase Image URL\n  isPublished Boolean  @default(false)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  creatorId String? // Creator (User) ID\n  modules   Module[]\n  purchases Purchase[]\n  cartItems CartItem[]\n  creator   User?      @relation(fields: [creatorId], references: [id])\n}\n\n// ==========================================\n// MODULE MODEL (Ek course ke andar multiple modules ho sakte hain)\n// ==========================================\nmodel Module {\n  id        String   @id @default(uuid())\n  title     String\n  order     Int // Module ko sort karne ke liye (1, 2, 3...)\n  courseId  String\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  course Course  @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  videos Video[]\n}\n\n// ==========================================\n// VIDEO MODEL (Lesson jo Bunny.net par hoga)\n// ==========================================\nmodel Video {\n  id            String   @id @default(uuid())\n  title         String\n  videoUrl      String // Bunny.net ka HLS stream URL\n  duration      Int? // Seconds mein\n  order         Int // Sort order\n  isPublished   Boolean  @default(true) // Naya field\n  isVerified    Boolean  @default(false) // Admin approval for first video\n  isFreePreview Boolean  @default(false) // Kya ye video bina kharide dekhi ja sakti hai?\n  moduleId      String\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  module   Module     @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  progress Progress[]\n}\n\n// ==========================================\n// PURCHASE MODEL (Payments Track karne ke liye)\n// ==========================================\nmodel Purchase {\n  id              String   @id @default(uuid())\n  userId          String\n  courseId        String\n  amount          Float\n  status          String   @default(\"PENDING\") // SUCCESS, FAILED\n  cashfreeOrderId String?  @unique // Cashfree ka order ID yaha aayega\n  createdAt       DateTime @default(now())\n  updatedAt       DateTime @updatedAt\n\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  course Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, courseId]) // Ek user ek course ko ek hi baar kharid sakta hai\n}\n\n// ==========================================\n// PROGRESS MODEL (Video kitni dekh li user ne)\n// ==========================================\nmodel Progress {\n  id          String   @id @default(uuid())\n  userId      String\n  videoId     String\n  isCompleted Boolean  @default(false)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  user  User  @relation(fields: [userId], references: [id], onDelete: Cascade)\n  video Video @relation(fields: [videoId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, videoId])\n}\n\n// ==========================================\n// CART MODELS\n// ==========================================\nmodel Cart {\n  id        String   @id @default(uuid())\n  userId    String   @unique\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  user  User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  items CartItem[]\n}\n\nmodel CartItem {\n  id        String   @id @default(uuid())\n  cartId    String\n  courseId  String\n  createdAt DateTime @default(now())\n\n  cart   Cart   @relation(fields: [cartId], references: [id], onDelete: Cascade)\n  course Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  @@unique([cartId, courseId])\n}\n",
